#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct {
    void (*func)();
    char name[64];
} Object;

void win() {
    printf("You win!\n");
}

int main() {
    Object *obj1 = malloc(sizeof(Object));
    Object *obj2 = malloc(sizeof(Object));

    // 初始化obj2的函数指针
    obj2->func = NULL;

    // 存在堆溢出：输入到obj1->name时未检查长度
    char input[128];
    gets(input);  // 危险！可溢出到obj2
    strcpy(obj1->name, input);

    // 如果溢出覆盖了obj2->func，则调用obj2->func()会执行攻击者指定的函数
    if (obj2->func) {
        obj2->func();
    }

    return 0;
}


